mapper.select:
SELECT * FROM travel_trips
WHERE user_id = #{userId}
ORDER BY created_at DESC

mapper.update:
UPDATE travel_trips
title = #{title}, destination = #{destination}, start_date = #{startDate}, end_date = #{endDate}, travelers = #{travelers}, budget_per_person = #{budgetPerPerson}, travel_style = #{travelStyle}, currency = #{currency}, exchange_rate = #{exchangeRate}, status = #{status}, info_content = #{infoContent}, updated_at = CURRENT_TIMESTAMP
WHERE id = #{id} AND user_id = #{userId}

mapper.select:
SELECT * FROM travel_itinerary
WHERE trip_id = #{tripId}
ORDER BY day_number ASC, display_order ASC, time_start ASC

mapper.update:
UPDATE travel_itinerary
day_number = #{dayNumber}, date = #{date}, time_start = #{timeStart}, time_end = #{timeEnd}, activity = #{activity}, category = #{category}, cost = #{cost}, memo = #{memo}, display_order = #{displayOrder},
WHERE id = #{id}

mapper.select:
SELECT * FROM travel_checklist
WHERE trip_id = #{tripId}
ORDER BY category ASC, display_order ASC

mapper.update:
UPDATE travel_checklist
item = #{item}, status = #{status}, category = #{category}, display_order = #{displayOrder},
WHERE id = #{id}

mapper.select:
SELECT * FROM travel_expenses
WHERE trip_id = #{tripId}
ORDER BY expense_date ASC, created_at ASC

mapper.update:
UPDATE travel_expenses
expense_date = #{expenseDate}, item = #{item}, category = #{category}, payment_method = #{paymentMethod}, amount = #{amount}, amount_krw = #{amountKrw}, amount_per_person = #{amountPerPerson}, amount_krw_per_person = #{amountKrwPerPerson}, memo = #{memo}, settled = #{settled},
WHERE id = #{id}
